collectionProcessors.formula:
OR(
    /* Scenario 1: Wrong Product, Batch, or Delivery mismatches */
    AND(
        OR(
            ISPICKVAL({!$Record.Category__c}, "Wrong Product"),
            ISPICKVAL({!$Record.Category__c}, "Wrong Batch"),
            ISPICKVAL({!$Record.Category__c}, "Wrong Delivery")
        ),
        NOT(ISPICKVAL({!currentItem_Filter_Invoice_Items.Status__c}, "Missing")),
        NOT(ISPICKVAL({!currentItem_Filter_Invoice_Items.Status__c}, "Additional"))
    ),

    /* Scenario 2: Additional Quantity/Product mismatch */
    AND(
        ISPICKVAL({!$Record.Category__c}, "Additional Quantity/Product"),
        NOT(ISPICKVAL({!currentItem_Filter_Invoice_Items.Status__c}, "Additional"))
    ),

    /* Scenario 3: Damaged/Broken mismatch */
    AND(
        ISPICKVAL({!$Record.Category__c}, "Damaged/Broken"),
        NOT(ISPICKVAL({!currentItem_Filter_Invoice_Items.Status__c}, "Damaged"))
    ),

    /* Scenario 4: Documentation Issue mismatches */
    AND(
        OR(
            ISPICKVAL({!$Record.Category__c}, "Documentation Issue - Wrong Credit Note"),
            ISPICKVAL({!$Record.Category__c}, "Documentation Issue - Wrong Receipt"),
            ISPICKVAL({!$Record.Category__c}, "Documentation Issue - Wrong/Missing Invoice")
        ),
        NOT(ISPICKVAL({!currentItem_Filter_Invoice_Items.Status__c}, "Wrong Docs"))
    ),

    /* Scenario 5: Labeling Issue mismatches */
    AND(
        OR(
            ISPICKVAL({!$Record.Category__c}, "Labeling Issue - Damaged"),
            ISPICKVAL({!$Record.Category__c}, "Labeling Issue - Not Labeled"),
            ISPICKVAL({!$Record.Category__c}, "Labeling Issue - Wrong Price Tag"),
            ISPICKVAL({!$Record.Category__c}, "Labeling Issue - Wrong Registration Number")
        ),
        NOT(ISPICKVAL({!currentItem_Filter_Invoice_Items.Status__c}, "Mislabeling"))
    ),

    /* Scenario 6: Late Arrival mismatches */
    AND(
        OR(
            ISPICKVAL({!$Record.Category__c}, "Late Arrival - Customer Complaint"),
            ISPICKVAL({!$Record.Category__c}, "Late Arrival - Dispatch")
        ),
        NOT(ISPICKVAL({!currentItem_Filter_Invoice_Items.Status__c}, "Order Not Received"))
    ),

    /* Scenario 7: Missing Quantity mismatch */
    AND(
        ISPICKVAL({!$Record.Category__c}, "Missing Quantity"),
        NOT(ISPICKVAL({!currentItem_Filter_Invoice_Items.Status__c}, "Missing"))
    )
)
